  align-items: center !important;
}

.header::before {
  content: "";
  position: absolute;
  top: -50px;
  right: -50px;
  width: 220px;
  height: 220px;
  background: rgba(255, 255, 255, 0.12);
  border-radius: 50%;
}

.header::after {
  content: "";
  position: absolute;
  bottom: -80px;
  left: -80px;
  width: 260px;
  height: 260px;
  background: rgba(255, 255, 255, 0.08);
  border-radius: 50%;
}

.title {
  font-size: 44px;
  font-weight: 800;
  margin-bottom: 14px;
  position: relative;
  z-index: 2;
}

.subtitle {
  font-size: 18px;
  font-weight: 500;
  opacity: 0.9;
  position: relative;
  z-index: 2;
}

.logo {
  position: relative;
  z-index: 2;
  max-width: 120px; 
  height: auto;
}
@media (max-width: 640px) {
  .header {
    padding: 35px 25px;
    flex-direction: column; 
    text-align: center;
    gap: 20px;
  }
  
  .header > div {
    width: 100%; 
  }
  
  .title {
    font-size: 34px;
  }
  
  .subtitle {
    font-size: 16px;
  }
  
  .logo {
    max-width: 100px; 
    margin-top: 10px;
  }
}

.body {
  padding: 28px;
  display: flex;
  flex-direction: column;
  gap: 18px; 
}

@media (min-width: 640px) {
  .body {
    padding: 32px;
    gap: 22px;
  }
}

.body > * {
  width: 100%;
  display: block;
}

.buttons {
  padding: 25px 45px 45px 45px;
  display: flex;
  gap: 16px;
  justify-content: space-between;
}

@media (max-width: 640px) {
  .buttons {
    flex-direction: column;
    padding: 20px 25px 35px 25px;
  }
}

.button-1 {
  flex: 1;
  background: linear-gradient(to right, #0d9488, #1d4ed8);
  color: white;
  padding: 16px 22px;
  border-radius: 14px;
  font-weight: 700;
  font-size: 16px;
  border: none;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: 0px 10px 25px rgba(29, 78, 216, 0.25);
}

.button-1:hover {
  transform: translateY(-2px);
  box-shadow: 0px 14px 30px rgba(13, 148, 136, 0.35);
}

.button-1:active {
  transform: scale(0.98);
}

.button-2 {
  min-width: 160px;
  padding: 16px 22px;
  border-radius: 14px;
  font-weight: 700;
  font-size: 16px;
  border: 2px solid #cbd5e1;
  background: white;
  color: #1f2937;
  cursor: pointer;
  transition: all 0.3s ease;
}

.button-2:hover {
  border-color: #1d4ed8;
  color: #1d4ed8;
  background: rgba(29, 78, 216, 0.05);
}

.button-2:active {
  transform: scale(0.98);
}
.popup-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(15, 23, 42, 0.65);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 9999;
}

.popup-box {
  background: white;
  padding: 100px 35px;
  border-radius: 24px;
  width: 90%;
  max-width: 420px;
  text-align: center;
  box-shadow: 0px 20px 50px rgba(0, 0, 0, 0.25);
  animation: scaleIn 0.3s ease-in-out;
}
.popup-box h2 {
  font-size: 36px;
  margin-bottom: 15px;
  background: linear-gradient(to right, #0d9488, #1d4ed8);
  background-clip: text;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}
.popup-box p {
  font-size: 16px;
  margin-bottom: 25px;
  color: #334155;
  line-height: 1.6;
}
.popup-box button {
  background: linear-gradient(to right, #0d9488, #1d4ed8);
  color: white;
  border: none;
  padding: 12px 28px;
  border-radius: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
}

.popup-box button:hover {
  transform: translateY(-2px);
  box-shadow: 0px 10px 25px rgba(29, 78, 216, 0.35);
}

@keyframes scaleIn {
  from {
    transform: scale(0.8);
    opacity: 0;
  }
  to {
    transform: scale(1);
    opacity: 1;
  }
}
.logo {
  height: auto;
  width: auto;
  max-width: 100%;
  max-height: 70px; 
  position: relative;
  z-index: 10;
  object-fit: contain; 
}
@media screen and (max-width: 1024px) {
  .logo {
    max-height: 65px;
  }
}

@media screen and (max-width: 768px) {
  .logo {
    max-height: 60px;
  }
}

@media screen and (max-width: 480px) {
  .logo {
    max-height: 50px; 
    display: block;
    margin-left: 0; 
    margin-right: auto; 
  }
}

@media screen and (max-width: 480px) {
  .logo {
    max-height: 55px;
    margin-left: auto;
    margin-right: auto;
    display: block;
  }
}


@media screen and (max-width: 360px) {
  .logo {
    max-height: 45px;
  }
}

